import React,{useEffect,useState} from "react";
import axios from "axios";

function Admin(){

 const[orders,setOrders]=useState([]);

 const load=()=>{
  axios.get("http://localhost:8080/orders")
  .then(res=>setOrders(res.data));
 }

 useEffect(()=>{load();},[]);

 const markReady=(id)=>{
  axios.put("http://localhost:8080/orders/"+id+"/ready")
  .then(load);
 }

 return(
  <div className="mt-4">
   <h3>Admin Panel</h3>
   {orders.map(o=>(
    <div key={o.id}>
     {o.foodName} - {o.status}
     {o.status==="Preparing" &&
      <button className="btn btn-success btn-sm ms-2"
       onClick={()=>markReady(o.id)}>Mark Ready</button>}
    </div>
   ))}
  </div>
 );
}

export default Admin;
